#include <stdio.h>
#include <stdlib.h>

long long largestRectangle(int *h, int n) {
    long long maxArea = 0;
    int *st = (int *)malloc(n * sizeof(int));
    int top = -1;
    for (int i = 0; i < n; ++i) {
        while (top != -1 && h[i] < h[st[top]]) {
            int height = h[st[top--]];
            int width = (top == -1) ? i : i - st[top] - 1;
            long long area = (long long)height * width;
            if (area > maxArea) maxArea = area;
        }
        st[++top] = i;
    }
    while (top != -1) {
        int height = h[st[top--]];
        int width = (top == -1) ? n : n - st[top] - 1;
        long long area = (long long)height * width;
        if (area > maxArea) maxArea = area;
    }
    free(st);
    return maxArea;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int *heights = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &heights[i]);
        printf("%lld\n", largestRectangle(heights, N));
        free(heights);
    }
    return 0;
}

