#include <bits/stdc++.h>
using namespace std;

long long largestRectangle(const vector<int>& h) {
    long long maxArea = 0;
    vector<int> st;
    st.reserve(h.size());
    for (size_t i = 0; i < h.size(); ++i) {
        while (!st.empty() && h[i] < h[st.back()]) {
            int height = h[st.back()];
            st.pop_back();
            size_t width = st.empty() ? i : i - st.back() - 1;
            maxArea = max(maxArea, (long long)height * (long long)width);
        }
        st.push_back(i);
    }
    while (!st.empty()) {
        int height = h[st.back()];
        st.pop_back();
        size_t width = st.empty() ? h.size() : h.size() - st.back() - 1;
        maxArea = max(maxArea, (long long)height * (long long)width);
    }
    return maxArea;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int N; cin >> N;
        vector<int> heights(N);
        for (int &x : heights) cin >> x;
        cout << largestRectangle(heights) << '\n';
    }
    return 0;
}

